UPDATE nextjs_shop_cart c
JOIN nextjs_shop_product_option po ON c.product_option_id = po.product_option_id
SET c.quantity = LEAST(
	c.quantity + CASE c.product_option_id

		WHEN #{item.productOptionId} THEN #{item.quantity}

		ELSE 0
	END,
	po.stock
)
WHERE c.user_no = #{userNo}
	AND c.product_option_id IN

	#{item.productOptionId}

mapper.insert:
INSERT INTO nextjs_shop_cart (product_option_id, user_no, quantity) SELECT t.product_option_id, #{userNo}, LEAST(t.quantity, po.stock) AS quantity FROM (
SELECT #{item.productOptionId} AS product_option_id, #{item.quantity} AS quantity
) t JOIN nextjs_shop_product_option po ON po.product_option_id = t.product_option_id WHERE po.stock > 0

mapper.select:
SELECT t.product_option_id AS productOptionId, t.quantity AS requestedQuantity, po.stock AS stock, c.quantity AS cartQuantity FROM (
SELECT #{item.productOptionId} AS product_option_id, #{item.quantity} AS quantity
) t JOIN nextjs_shop_product_option po ON po.product_option_id = t.product_option_id LEFT JOIN nextjs_shop_cart c ON c.user_no = #{userNo} AND c.is_deleted = 0 AND c.product_option_id = t.product_option_id

